bool isEven(int number) {
    return number % 2 == 0;
}

int main() {
    for (int i = 1; i <= 10; i++) {
        if (isEven(i)) {
            cout << i << " is even\n";
        } else {
            cout << i << " is odd\n";
        }
    }
    return 0;
}

