    std::lock_guard<std::mutex> lock(mtx);
    std::cout << "Task " << id << " is running on thread " 
              << std::this_thread::get_id() << std::endl;
}

int main() {
    std::thread t1(printTask, 1);
    std::thread t2(printTask, 2);

    t1.join();
    t2.join();
    return 0;
}

